script:
frappe.ui.form.on("Hostel Admission", {
    refresh(frm) {
        if (frm.is_new()) return;

        if (["Draft", "Approved"].includes(frm.doc.admission_status) && frm.doc.hostel_room) {
            frm.add_custom_button("Check In", function() {
                frappe.confirm(
                    `Check in ${frm.doc.student_name} to Room ${frm.doc.hostel_room}?`,
                    () => {
                        frm.set_value("admission_status", "Checked In");
                        frm.save();
                    }
                );
            }).addClass("btn-primary");
        }

        if (frm.doc.admission_status === "Checked In") {
            frm.add_custom_button("Print Admission Slip", function() {
                frappe.route_options = {};
                frappe.set_route("print", "Hostel Admission", frm.doc.name);
            });
        }
    }
});
